#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buffer[105];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(buffer, sizeof(buffer), stdin)) break;
        size_t len = strlen(buffer);
        if (len && buffer[len-1] == '\n') buffer[--len] = '\0';
        int digits = 0, alphabets = 0, whitespaces = 0, special = 0;
        for (size_t i = 0; i < len; ++i) {
            unsigned char ch = buffer[i];
            if (isdigit(ch)) digits++;
            else if (isalpha(ch)) alphabets++;
            else if (isspace(ch)) whitespaces++;
            else special++;
        }
        printf("{'digits': %d, 'alphabets': %d, 'whitespaces': %d, 'special': %d}\n", digits, alphabets, whitespaces, special);
    }
    return 0;
}

