public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String first = br.readLine();
        if (first == null) return;
        int T = Integer.parseInt(first.trim());
        for (int tc = 0; tc < T; ++tc) {
            String line = br.readLine();
            if (line == null) line = "";
            int digits = 0, alphabets = 0, whitespaces = 0, special = 0;
            for (char ch : line.toCharArray()) {
                if (Character.isDigit(ch)) digits++;
                else if (Character.isAlphabetic(ch)) alphabets++;
                else if (Character.isWhitespace(ch)) whitespaces++;
                else special++;
            }
            System.out.println("{'digits': " + digits + ", 'alphabets': " + alphabets + ", 'whitespaces': " + whitespaces + ", 'special': " + special + "}");
        }
    }
}

