import sys

def analyze_string(s):
    if not isinstance(s, str):
        return "Error: Input must be a string."
    result = {'digits': 0, 'alphabets': 0, 'whitespaces': 0, 'special': 0}
    for ch in s:
        if ch.isdigit():
            result['digits'] += 1
        elif ch.isalpha():
            result['alphabets'] += 1
        elif ch.isspace():
            result['whitespaces'] += 1
        else:
            result['special'] += 1
    return result

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0].strip())
for i in range(1, T + 1):
    line = data[i] if i < len(data) else ''
    res = analyze_string(line)
    if isinstance(res, dict):
        print(f"{{'digits': {res['digits']}, 'alphabets': {res['alphabets']}, 'whitespaces': {res['whitespaces']}, 'special': {res['special']}}}")
