const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').split(/\n/);
let idx = 0;
const T = parseInt((input[idx++] || '').trim(), 10) || 0;
function analyzeString(str) {
  if (typeof str !== 'string') return "Error: Input must be a string.";
  let digits = 0, alphabets = 0, whitespaces = 0, special = 0;
  for (const ch of str) {
    if (/[0-9]/.test(ch)) digits++;
    else if (/[a-zA-Z]/.test(ch)) alphabets++;
    else if (/\s/.test(ch)) whitespaces++;
    else special++;
  }
  return `{'digits': ${digits}, 'alphabets': ${alphabets}, 'whitespaces': ${whitespaces}, 'special': ${special}}`;
}
let outputs = [];
for (let t = 0; t < T; ++t) {
  const line = input[idx++] ?? '';
  outputs.push(analyzeString(line));
}
